import {OjMessageBase} from "./OjMessageBase";

/**
 * This is the component WebElement for oj-message. Retrieve an instance of the class
 * using its convenience function:
 * ```javascript
 * await ojMessage(driver, By.css('oj-message'))
 * ```
 */
export class OjMessage extends OjMessageBase {
  /**
   * Dismiss the message
   */
  async doClose() {
    await this.whenReady();
    await this.getDriver().executeScript('arguments[0].close()', this);
    await this.whenBusyContextReady();
  }
}
